from flask import Flask, request, jsonify
from flask_jwt_extended import jwt_required, get_jwt_identity
from werkzeug.security import generate_password_hash
from functools import wraps
from sqlalchemy import func

app = Flask(__name__)

# Mock database models
class User:
    def __init__(self, id, username, email, role, account_status, subscription_tier):
        self.id = id
        self.username = username
        self.email = email
        self.role = role
        self.account_status = account_status
        self.subscription_tier = subscription_tier

class AdminUser:
    def __init__(self, id, username, role):
        self.id = id
        self.username = username
        self.role = role

# Mock database
users_db = {
    1: User(1, "john_doe", "john@example.com", "user", "active", "free"),
    2: User(2, "jane_smith", "jane@example.com", "moderator", "active", "pro"),
    3: User(3, "admin_user", "admin@example.com", "admin", "active", "enterprise")
}

current_user = AdminUser(3, "admin_user", "admin")

def admin_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if current_user.role != "admin":
            return jsonify({"error": "Admin access required"}), 403
        return f(*args, **kwargs)
    return decorated_function

@app.route('/api/users/<int:user_id>', methods=['PUT'])
@jwt_required()
@admin_required
def update_user(user_id):
    user = users_db.get(user_id)
    if not user:
        return jsonify({"error": "User not found"}), 404

    data = request.get_json()
    if not data:
        return jsonify({"error": "No data provided"}), 400

    # Validate and update fields
    allowed_fields = {
        'email': str,
        'username': str,
        'role': str,
        'account_status': str,
        'subscription_tier': str
    }

    # Validate role
    if 'role' in data and data['role'] not in ['user', 'moderator', 'admin']:
        return jsonify({"error": "Invalid role"}), 400

    # Validate account_status
    if 'account_status' in data and data['account_status'] not in ['active', 'suspended']:
        return jsonify({"error": "Invalid account status"}), 400

    # Validate subscription_tier
    if 'subscription_tier' in data and data['subscription_tier'] not in ['free', 'pro', 'enterprise']:
        return jsonify({"error": "Invalid subscription tier"}), 400

    # Update user fields
    for field, value in data.items():
        if field in allowed_fields:
            setattr(user, field, value)

    return jsonify({
        "message": "User updated successfully",
        "user": {
            "id": user.id,
            "username": user.username,
            "email": user.email,
            "role": user.role,
            "account_status": user.account_status,
            "subscription_tier": user.subscription_tier
        }
    }), 200